const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const incomingLogId = body.incomingLogId;
const from = body.from || '';
const subject = body.subject || '';
const textPlain = body.textPlain || '';
const classification = body.classification || {};
const threadId = body.threadId || null;
const emailId = body.emailId || null;

if (!tenantId || !from) {
  return [{ json: { success: false, error: 'tenantId et from requis' } }];
}

return [{ json: {
  tenantId, incomingLogId, from, subject, textPlain,
  classification, threadId, emailId, valid: true
} }];

const email = $('02. Valider').first().json;
const ctx = $input.first().json;
const aiConfig = ctx.ai_config || {};
const history = ctx.email_history || [];

const historyText = history.length > 0
  ? history.map((h, i) => `[${i+1}] Sujet: ${h.subject} | De: ${h.from} | Repondu: ${h.reply_sent ? 'oui' : 'non'} | Date: ${h.created_at}`).join('\n')
  : 'Aucun historique avec cet expediteur.';

const businessInfo = [
  ctx.tenant_name ? `Entreprise: ${ctx.tenant_name}` : '',
  ctx.tenant_email ? `Email: ${ctx.tenant_email}` : '',
  ctx.tenant_phone ? `Tel: ${ctx.tenant_phone}` : '',
  ctx.tenant_address ? `Adresse: ${ctx.tenant_address}` : '',
  aiConfig.businessContext ? `Activite: ${aiConfig.businessContext}` : '',
  aiConfig.faq ? `FAQ: ${aiConfig.faq}` : '',
  aiConfig.signature ? `Signature: ${aiConfig.signature}` : ''
].filter(Boolean).join('\n');

return [{ json: {
  ...email,
  aiConfig,
  businessInfo,
  historyText,
  tenantName: ctx.tenant_name || 'Notre entreprise',
  tenantEmail: ctx.tenant_email || '',
  signature: aiConfig.signature || `Cordialement,\n${ctx.tenant_name || ''}`,
  model: aiConfig.model || 'gpt-4o-mini',
  apiKey: aiConfig.openaiApiKey || '',
  language: aiConfig.language || 'fr',
  tone: aiConfig.tone || 'professionnel',
  maxLength: aiConfig.maxReplyLength || 500
} }];

