const email = $('04. Preparer contexte').first().json;
const aiResponse = $input.first().json;

let reply = {};
try {
  const content = aiResponse.choices?.[0]?.message?.content || '{}';
  reply = JSON.parse(content);
} catch (e) {
  reply = {
    subject: `Re: ${email.subject}`,
    body_text: '',
    body_html: '',
    confidence: 0,
    needs_human_review: true,
    reason: 'Erreur parsing reponse IA'
  };
}

// Ajouter signature si pas deja presente
if (email.signature && reply.body_text && !reply.body_text.includes(email.tenantName)) {
  reply.body_text += '\n\n' + email.signature;
  reply.body_html += '<br><br>' + email.signature.replace(/\n/g, '<br>');
}

const action = reply.needs_human_review ? 'queue_human' : 'send_auto';

return [{ json: {
  tenantId: email.tenantId,
  incomingLogId: email.incomingLogId,
  from: email.from,
  originalSubject: email.subject,
  threadId: email.threadId,
  emailId: email.emailId,
  reply,
  action,
  tokensUsed: aiResponse.usage?.total_tokens || 0,
  tenantEmail: email.tenantEmail
} }];

const data = $('06. Parser reponse').first().json;

return [{ json: {
  success: true,
  data: {
    incomingLogId: data.incomingLogId,
    action: data.action,
    replySubject: data.reply.subject,
    confidence: data.reply.confidence,
    needsHumanReview: data.reply.needs_human_review,
    reason: data.reply.reason || null,
    to: data.from,
    tenantId: data.tenantId,
    replyText: data.reply.body_text,
    replyHtml: data.reply.body_html
  }
} }];
